import{_ as e,o as t,c as o,ai as l}from"./chunks/framework.CsYGeNYI.js";const y=JSON.parse('{"title":"Gateway 网关锁","description":"","frontmatter":{"read_when":["运行或调试 Gateway 网关进程","调查单实例强制执行"],"summary":"使用 WebSocket 监听器绑定的 Gateway 网关单例保护","title":"Gateway 网关锁","x-i18n":{"generated_at":"2026-02-03T07:47:52Z","model":"claude-opus-4-5","provider":"pi","source_hash":"15fdfa066d1925da8b4632073a876709f77ca8d40e6828c174a30d953ba4f8e9","source_path":"gateway/gateway-lock.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/gateway-lock.md","filePath":"zh-CN/gateway/gateway-lock.md","lastUpdated":1771906665000}'),r={name:"zh-CN/gateway/gateway-lock.md"};function i(c,a,d,s,n,h){return t(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="gateway-网关锁" tabindex="-1"><a class="header-anchor" href="#gateway-网关锁">#</a> Gateway 网关锁</h1><p>最后更新：2025-12-11</p><h2 id="原因" tabindex="-1"><a class="header-anchor" href="#原因">#</a> 原因</h2><ul><li>确保同一主机上每个基础端口只运行一个 Gateway 网关实例；额外的 Gateway 网关必须使用隔离的配置文件和唯一的端口。</li><li>在崩溃/SIGKILL 后不留下过时的锁文件。</li><li>当控制端口已被占用时快速失败并给出清晰的错误。</li></ul><h2 id="机制" tabindex="-1"><a class="header-anchor" href="#机制">#</a> 机制</h2><ul><li>Gateway 网关在启动时立即使用独占 TCP 监听器绑定 WebSocket 监听器（默认 <code>ws://127.0.0.1:18789</code>）。</li><li>如果绑定因 <code>EADDRINUSE</code> 失败，启动会抛出 <code>GatewayLockError(&quot;another gateway instance is already listening on ws://127.0.0.1:&lt;port&gt;&quot;)</code>。</li><li>操作系统在任何进程退出时（包括崩溃和 SIGKILL）自动释放监听器——不需要单独的锁文件或清理步骤。</li><li>关闭时，Gateway 网关关闭 WebSocket 服务器和底层 HTTP 服务器以及时释放端口。</li></ul><h2 id="错误表面" tabindex="-1"><a class="header-anchor" href="#错误表面">#</a> 错误表面</h2><ul><li>如果另一个进程持有端口，启动会抛出 <code>GatewayLockError(&quot;another gateway instance is already listening on ws://127.0.0.1:&lt;port&gt;&quot;)</code>。</li><li>其他绑定失败会显示为 <code>GatewayLockError(&quot;failed to bind gateway socket on ws://127.0.0.1:&lt;port&gt;: …&quot;)</code>。</li></ul><h2 id="运维说明" tabindex="-1"><a class="header-anchor" href="#运维说明">#</a> 运维说明</h2><ul><li>如果端口被<em>另一个</em>进程占用，错误是相同的；释放端口或使用 <code>opensoul gateway --port &lt;port&gt;</code> 选择另一个端口。</li><li>macOS 应用在启动 Gateway 网关之前仍维护自己的轻量级 PID 保护；运行时锁由 WebSocket 绑定强制执行。</li></ul>',10)])])}const u=e(r,[["render",i]]);export{y as __pageData,u as default};
